local xml = require("pullrequest.xml")
local cjson = require("cjson")

function process_request(req)
    local body = req:get_body_data()
    if not body then
        ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local xml_doc, err = xml.parse(body)
    if not xml_doc then
        ngx.log(ngx.ERR, "Error parsing XML: ", err)
        ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local soap = xml_doc:get_element_by_name("soap")
    if not soap then
        ngx.log(ngx.ERR, "Error finding 'soap' element.")
        ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    local data = {}
    for child in soap:iter() do
        if child:get_name() ~= "#text" then -- ignore text nodes
            local tagName, attr = child:get_name(), child:get_attributes()
            table.insert(data, {tagName, attr})
        end
    end

    ngx.req.body_file = io.open("/tmp/request.json", "w")
    ngx.req.body_file:write(cjson.encode(data))
    ngx.req.body_file:close()
end

ngx.connection_ctx._init = function(self)
    self:_set_keepalive(true)
    self:register_request_handler("request", process_request)
end